INSERT INTO `plos` (`id`, `program_id`, `code`, `description`) VALUES
(1, 12, 'PLO1', 'Vận dụng được các kiến thức cơ bản về Chủ nghĩa Mác-Lênin, tư tưởng Hồ Chí Minh, đường lối chủ trương của Đảng và Nhà nước, về pháp luật, an ninh-quốc phòng, giáo dục thể chất trong nghề nghiệp và cuộc sống.'),
(2, 12, 'PLO2', 'Áp dụng được kiến thức nền tảng về toán học, lí thuyết xác suất và thống kê toán, tin học và lập trình ứng dụng, tâm lí học, tiếng Anh, kinh tế, kinh doanh, khởi nghiệp trong hoạt động chuyên môn.'),
(3, 12, 'PLO3', 'Vận dụng được các các kiến thức nền tảng về hệ thống thông tin quản lý như hệ cơ sở dữ liệu, các phương pháp định lượng trong quản lí, tạo lập và thiết kế web, tổ chức và quản trị kinh doanh, hệ thống thông tin và các quy trình kinh doanh vào việc cải tiến quản lí, điều hành các hoạt động sản xuất-kinh doanh.'),
(4, 12, 'PLO4', 'Áp dụng được vào thực tế các kiến thức chuyên sâu về mô hình hóa, thiết kế và quản lí các hệ thống thông tin, lập trình nâng cao, các nguyên lí an toàn thông tin, quản trị dự án CNTT, thiết kế đa phương tiện và phát triển web.'),
(5, 12, 'PLO5', 'Kết nối được các kiển thức chuyên sâu về các giải pháp kinh doanh và hệ thống thông tin cho doanh nghiệp, phân tích kinh doanh hỗ trợ ra quyết định và các kiến thức chuyên sâu theo lựa chọn về quản lí thông tin để giải quyết có hiệu quả các bài toán thực tế.'),
(6, 12, 'PLO6', 'Thực hiện được việc nhận diện, phân tích và giải quyết vấn đề một cách khoa học và có khả năng thiết kế, vận hành, cải tiến các hệ thống và quy trình trong lĩnh vực hệ thống thông tin quản lý.'),
(7, 12, 'PLO7', 'Có khả năng phản biện, phê phán và thực hiện các giải pháp thay thế, khả năng cải tiến, đổi mới trong hoạt động nghề nghiệp, quản trị thay đổi và dự đoán xu thế phát triển ngành nghề.'),
(8, 12, 'PLO8', 'Có khả năng dẫn dắt, khởi nghiệp, tạo việc làm, làm thành thạo việc truyền đạt vấn đề và đưa ra giải pháp thực hiện, có khả năng lập kế hoạch, theo dõi và đánh giá kết quả thực hiện công việc.'),
(9, 12, 'PLO9', 'Thực hiện thành thạo các kĩ năng cần thiết như kĩ năng giao tiếp ứng xử, kĩ năng thuyết trình, kĩ năng viết báo cáo và văn bản, kĩ năng sử dụng công nghệ số hiệu quả.'),
(10, 12, 'PLO10', 'Làm quen với việc học và tự học một cách hiệu quả, có khả năng quản lí thời gian và tự đào tạo, khả năng quan sát và học hỏi từ thực tiễn để học tập suốt đời.'),
(11, 12, 'PLO11', 'Có năng lực sử dụng tiếng Anh trình độ tương đương bậc 4/6, có khả năng sử dụng tiếng Anh để làm việc trong các tổ chức, doanh nghiệp có yếu tố quốc tế.'),
(12, 12, 'PLO12', 'Có năng lực làm việc độc lập hoặc theo nhóm trong điều kiện thay đổi, chịu trách nhiệm cá nhân và trách nhiệm đối với nhóm, có tinh thần chủ động và sáng kiến.'),
(13, 12, 'PLO13', 'Có năng lực tự chủ, tự định hướng, đưa ra kết luận chuyên môn, thích nghi với môi trường áp lực cao, có năng lực hướng dẫn, giám sát người khác.'),
(14, 12, 'PLO14', 'Có trách nhiệm với đơn vị công tác, ý thức tổ chức kỷ luật, trung thực, tận tâm, công bằng, minh bạch, tuân thủ pháp luật và nội quy đơn vị.'),
(15, 12, 'PLO15', 'Có phẩm chất đạo đức cá nhân và nghề nghiệp, chính trực, có trách nhiệm cộng đồng và xã hội, lập trường chính trị vững vàng, ý thức xây dựng và bảo vệ đất nước.'),
(16, 10, 'PLO1', 'Vận dụng các kiến thức cơ bản về khoa học xã hội, khoa học chính trị, pháp luật và ngoại ngữ (tiếng Anh) trong học tập, nghiên cứu và tác nghiệp.'),
(17, 10, 'PLO2', 'Áp dụng các kiến thức cơ bản về kinh doanh quốc tế để học tập, nghiên cứu và làm việc tại các tổ chức và doanh nghiệp.'),
(18, 10, 'PLO3', 'Áp dụng các kiến thức về môi trường văn hoá, luật pháp, các yếu tố liên quan đến toàn cầu hoá, nền kinh tế 4.0, sự phát triển công nghệ, đổi mới và phát triển bền vững đến hoạt động kinh doanh quốc tế.'),
(19, 10, 'PLO4', 'Vận dụng các kiến thức chuyên sâu về kinh doanh quốc tế và quản trị kinh doanh quốc tế, tài chính, marketing, thương mại quốc tế, quản trị nguồn nhân lực để phân tích và đề xuất giải pháp cho các vấn đề kinh doanh.'),
(20, 10, 'PLO5', 'Phân tích các vấn đề kế toán và kiểm toán, các vấn đề về quản trị rủi ro trong đầu tư, đưa ra các giải pháp phù hợp trong bối cảnh thực tế.'),
(21, 10, 'PLO6', 'Đánh giá các mô hình, chiến lược, phương thức kinh doanh trong kinh doanh quốc tế tại Việt Nam và nước ngoài.'),
(22, 10, 'PLO7', 'Áp dụng kĩ năng tổng hợp và phân tích thông tin và dữ liệu liên quan đến kinh doanh quốc tế để đưa ra kết luận và giải pháp một cách khoa học.'),
(23, 10, 'PLO8', 'Vận dụng tư duy sáng tạo, tư duy nhìn nhận vấn đề một cách tổng quát, đổi mới trong tiếp cận và ứng dụng công nghệ, giải quyết vấn đề thực tiễn.'),
(24, 10, 'PLO9', 'Phát triển kỹ năng dẫn dắt, khởi nghiệp, tạo việc làm cho mình và người khác.'),
(25, 10, 'PLO10', 'Xây dựng kỹ năng giao tiếp, kĩ năng đàm phán, thuyết phục; Có năng lực sử dụng tiếng Anh trình độ tương đương bậc 4/6.'),
(26, 10, 'PLO11', 'Xác định khả năng làm việc nhóm, lập kế hoạch, giao việc, tư duy và giải quyết vấn đề, kiểm soát và quản trị hiệu quả.'),
(27, 10, 'PLO12', 'Vận dụng kỹ năng sử dụng phần mềm văn phòng, các kỹ thuật, phương pháp nghiên cứu và phân tích định lượng trong phân tích kinh doanh.'),
(28, 10, 'PLO13', 'Xác định khả năng tự chủ trong nghiên cứu, sử dụng thành thạo kiến thức để đề xuất giải pháp cho các vấn đề kinh doanh quốc tế.'),
(29, 10, 'PLO14', 'Xác định năng lực phát hiện, giải quyết vấn đề; rút ra những nguyên tắc, quy luật; đưa ra được những sáng kiến có giá trị.'),
(30, 10, 'PLO15', 'Xác định phẩm chất đạo đức tốt, trung thực, có trách nhiệm, chủ động, chính trực trong học tập và công việc.'),
(31, 11, 'PLO1', 'Vận dụng các lí thuyết, phương pháp luận của chủ nghĩa duy vật biện chứng và chủ nghĩa duy vật lịch sử; pháp luật, CNTT trong học tập và tác nghiệp.'),
(32, 11, 'PLO2', 'Liên kết các kiến thức kinh tế, tài chính, quản trị, luật pháp với nghiệp vụ, quy trình và hệ thống trong kế toán, phân tích và kiểm toán.'),
(33, 11, 'PLO3', 'Lý giải vai trò và ảnh hưởng của môi trường kinh tế, luật pháp, xã hội, công nghệ đến Báo cáo tài chính và quy trình kiểm toán.'),
(34, 11, 'PLO4', 'Phân biệt các lý thuyết, nguyên tắc, công cụ của Kế toán – Kiểm toán để lập Báo cáo tài chính, thực hiện quy trình kiểm toán.'),
(35, 11, 'PLO5', 'Dự báo mối quan hệ giữa các vấn đề kế toán-kiểm toán với quản trị và ra quyết định trong doanh nghiệp.'),
(36, 11, 'PLO6', 'Đánh giá các lý thuyết, nguyên tắc, công cụ phân tích để phân tích dữ liệu kế toán, tài chính, kinh tế phục vụ cho quản trị doanh nghiệp.'),
(37, 11, 'PLO7', 'Thiết kế hệ thống thông tin kế toán, lập và phân tích Báo cáo tài chính; thực hiên quy trình kiểm toán trên cơ sở tuân thủ đạo đức nghề nghiệp.'),
(38, 11, 'PLO8', 'Phân tích và lập báo cáo phân tích dữ liệu đáp ứng yêu cầu quản trị doanh nghiệp và ra quyết định.'),
(39, 11, 'PLO9', 'Thực hành tư duy sáng tạo, tư duy phản biện, tư duy hệ thống, đổi mới trong tiếp cận và ứng dụng công nghệ.'),
(40, 11, 'PLO10', 'Thực hành kỹ năng giao tiếp, kĩ năng đàm phán; Có năng lực sử dụng tiếng Anh trình độ tương đương bậc 4/6.'),
(41, 11, 'PLO11', 'Thực hành kĩ năng làm việc nhóm, lập kế hoạch, giao việc, tư duy và giải quyết vấn đề; có khả năng dẫn dắt và tạo việc làm.'),
(42, 11, 'PLO12', 'Vận dụng kỹ năng sử dụng phần mềm kế toán, phần mềm phân tích dữ liệu; các kỹ thuật, phương pháp phân tích định lượng.'),
(43, 11, 'PLO13', 'Khả năng tự học tập, tự chủ trong nghiên cứu, sử dụng thành thạo kiến thức để tìm tòi và đưa ra giải pháp trong thực tiễn công việc.'),
(44, 11, 'PLO14', 'Thực hành năng lực phát hiện, giải quyết vấn đề; đưa ra được những sáng kiến có giá trị để giải quyết vướng mắc.'),
(45, 11, 'PLO15', 'Thực hành các phẩm chất đạo đức tốt, trung thực, có trách nhiệm, chủ động, chính trực trong học tập và công việc.'),
(46, 13, 'PLO1', 'Vận dụng được các kiến thức cơ bản về Chủ nghĩa Mác-Lênin, tư tưởng Hồ Chí Minh, đường lối chủ trương của Đảng và Nhà nước.'),
(47, 13, 'PLO2', 'Áp dụng kiến thức thực tế và lí thuyết vững chắc về ngoại ngữ, toán, vật lý, thống kê, tin học, xử lý tín hiệu số.'),
(48, 13, 'PLO3', 'Lựa chọn và thực thi giải pháp kĩ thuật phù hợp để giải quyết các vấn đề liên quan tới Tin học và Kỹ thuật máy tính.'),
(49, 13, 'PLO4', 'Vận dụng được các kiến thức về lập kế hoạch, tổ chức và giám sát các quá trình trong các hoạt động chuyên môn.'),
(50, 13, 'PLO5', 'Vận dụng được các kiến thức cơ bản về quản lý, điều hành hoạt động chuyên môn liên quan tới phát triển dự án tại doanh nghiệp.'),
(51, 13, 'PLO6', 'Nhận diện, phân tích và giải quyết vấn đề một cách khoa học; thiết kế, vận hành, cải tiến các hệ thống và quy trình.'),
(52, 13, 'PLO7', 'Thiết lập kĩ năng phản biện, lựa chọn các giải pháp thay thế, cải tiến, đổi mới; quản trị thay đổi, cập nhật xu thế ngành nghề.'),
(53, 13, 'PLO8', 'Thực hiện việc dẫn dắt, khởi nghiệp; truyền đạt vấn đề và đưa ra giải pháp; lập kế hoạch, theo dõi và đánh giá kết quả.'),
(54, 13, 'PLO9', 'Thành thạo các kĩ năng giao tiếp ứng xử, thuyết trình, viết báo cáo, sử dụng công nghệ số hiệu quả.'),
(55, 13, 'PLO10', 'Làm quen với việc học và tự học, quản lí thời gian, tự đào tạo, quan sát và học hỏi từ thực tiễn để học tập suốt đời.'),
(56, 13, 'PLO11', 'Đạt trình độ tiếng Anh bậc 4 hoặc cao hơn theo Khung năng lực ngoại ngữ 6 bậc dùng cho Việt Nam.'),
(57, 13, 'PLO12', 'Làm việc độc lập hoặc theo nhóm, chịu trách nhiệm cá nhân và nhóm, trung thực trong phân tích và đưa ra kết quả.'),
(58, 13, 'PLO13', 'Xây dựng khả năng tự chủ, đưa ra kết luận chuyên môn, bảo vệ quan điểm cá nhân, chịu áp lực công việc cao.'),
(59, 13, 'PLO14', 'Xây dựng trách nhiệm với đơn vị công tác, kỷ luật, trung thực, tận tâm, tuân thủ pháp luật và nội quy.'),
(60, 13, 'PLO15', 'Xây dựng phẩm chất đạo đức nghề nghiệp: kiên trì, tự tin, chính trực, ý thức xây dựng và bảo vệ đất nước.'),
(61, 14, 'PLO1', 'Vận dụng được các kiến thức cơ bản về khoa học xã hội, khoa học chính trị và pháp luật trong học tập, nghiên cứu và tác nghiệp.'),
(62, 14, 'PLO2', 'Vận dụng kiến thức Toán, Thống kê, Kinh tế, CNTT để xây dựng và sử dụng các mô hình, công cụ phân tích dữ liệu.'),
(63, 14, 'PLO3', 'Lựa chọn và thực thi giải pháp phân tích dữ liệu phù hợp để giải quyết các thách thức tiềm ẩn liên quan tới kinh doanh.'),
(64, 14, 'PLO4', 'Vận dụng được các kiến thức về lập kế hoạch, tổ chức và giám sát các quá trình, tự học, sáng tạo, thích nghi với môi trường.'),
(65, 14, 'PLO5', 'Vận dụng được các kiến thức cơ bản về quản lí, điều hành hoạt động chuyên môn: quản lý dự án KHDL, chuỗi cung ứng...'),
(66, 14, 'PLO6', 'Giải quyết các vấn đề phức tạp thông qua lập luận tư duy sáng tạo, khả năng nghiên cứu, tư duy hệ thống.'),
(67, 14, 'PLO7', 'Thực hiện dẫn dắt, khởi nghiệp, tạo việc làm cho mình và cho người khác; có tinh thần lập nghiệp.'),
(68, 14, 'PLO8', 'Hình thành kĩ năng phản biện, phê phán, và sử dụng các giải pháp thay thế trong môi trường không xác định.'),
(69, 14, 'PLO9', 'Biết đánh giá chất lượng công việc sau khi hoàn thành và kết quả thực hiện của các thành viên trong nhóm.'),
(70, 14, 'PLO10', 'Thành thạo truyền đạt vấn đề và giải pháp tới người khác; phổ biến kiến thức, kĩ năng trong thực hiện nhiệm vụ.'),
(71, 14, 'PLO11', 'Có năng lực sử dụng tiếng Anh với trình độ tương đương bậc 4/6 theo khung năng lực ngoại ngữ 6 bậc.'),
(72, 14, 'PLO12', 'Làm việc độc lập hoặc theo nhóm, chịu trách nhiệm cá nhân và nhóm, trung thực trong phân tích dữ liệu.'),
(73, 14, 'PLO13', 'Hướng dẫn, giám sát những người khác thực hiện nhiệm vụ xác định.'),
(74, 14, 'PLO14', 'Tự định hướng, tự chủ trong nghiên cứu, đưa ra kết luận chuyên môn và bảo vệ được quan điểm cá nhân.'),
(75, 14, 'PLO15', 'Lập kế hoạch, điều phối, quản lí các nguồn lực, đánh giá và cải thiện hiệu quả các hoạt động.'),
(76, 17, 'PLO1', 'Vận dụng được các kiến thức cơ bản về Chủ nghĩa Mác-Lênin, tư tưởng Hồ Chí Minh, pháp luật, an ninh-quốc phòng.'),
(77, 17, 'PLO2', 'Áp dụng được kiến thức cơ bản về toán học, tin học, vật lý, hóa học, cơ học, xác suất thống kê trong công việc kỹ thuật.'),
(78, 17, 'PLO3', 'Áp dụng các kiến thức về nguyên lý tự động hóa, tính toán số; vận dụng thành thạo lập trình trong chuyên môn.'),
(79, 17, 'PLO4', 'Áp dụng nguyên lý đo lường, cảm biến, điều khiển, mạng máy tính, xử lý tín hiệu số, ioT trong công việc.'),
(80, 17, 'PLO5', 'Áp dụng kiến thức chuyên sâu về tự động hóa và tin học (PLC, robot, AI, dữ liệu lớn) trong thiết kế, vận hành hệ thống.'),
(81, 17, 'PLO6', 'Giải quyết vấn đề chuyên môn liên quan đến thiết kế, vận hành, cải tiến các thiết bị, quy trình trong sản xuất.'),
(82, 17, 'PLO7', 'Tổng hợp và lựa chọn giải pháp kỹ thuật phù hợp; quản trị thay đổi và khắc phục sự cố thiết bị.'),
(83, 17, 'PLO8', 'Lập kế hoạch, đánh giá kết quả thực hiện công việc của cá nhân/đội nhóm; cập nhật xu thế phát triển ngành nghề.'),
(84, 17, 'PLO9', 'Thuyết trình, giao tiếp hiệu quả trong phối hợp làm việc và báo cáo áp dụng các công nghệ cập nhật.'),
(85, 17, 'PLO10', 'Tự học và chủ động tìm tòi cái mới, từ lý thuyết và thực tiễn để học tập suốt đời.'),
(86, 17, 'PLO11', 'Có năng lực sử dụng tiếng Anh trình độ bậc 4/6, làm việc trong môi trường hội nhập quốc tế.'),
(87, 17, 'PLO12', 'Làm việc độc lập hoặc theo nhóm hiệu quả, phối hợp để đạt mục tiêu chung; hướng dẫn đội nhóm.'),
(88, 17, 'PLO13', 'Thích nghi nhanh với môi trường làm việc quốc tế đa văn hóa, giải quyết nhiều công việc theo tiến độ.'),
(89, 17, 'PLO14', 'Thực hiện nghiêm các quy định pháp luật và nội quy; công khai minh bạch và trách nhiệm với công việc.'),
(90, 17, 'PLO15', 'Thực hiện công việc kiên trì, linh hoạt, trung thực; có trách nhiệm cộng đồng và xã hội.'),
(91, 18, 'PLO1', 'VẬN DỤNG kiến thức cơ bản về khoa học xã hội, khoa học chính trị, năng lực số, và pháp luật trong học tập, nghiên cứu.'),
(92, 18, 'PLO2', 'ĐÁNH GIÁ những hiện tượng ngôn ngữ, văn hóa, xã hội vào lĩnh vực Ngôn ngữ Anh chuyên sâu Kinh doanh – CNTT.'),
(93, 18, 'PLO3', 'VẬN DỤNG thành thạo tiếng Anh tối thiểu bậc 5 và ngoại ngữ thứ hai tối thiểu bậc 3 vào hoạt động nghề nghiệp.'),
(94, 18, 'PLO4', 'ÁP DỤNG các kiến thức cơ bản về kinh doanh, công nghệ thông tin vào nghề nghiệp liên quan tới Ngôn ngữ Anh.'),
(95, 18, 'PLO5', 'HỆ THỐNG HÓA kiến thức lý thuyết cơ bản, chuyên sâu và thực tế để phát triển chuyên môn nghiên cứu và nghề nghiệp.'),
(96, 18, 'PLO6', 'PHÂN TÍCH các vấn đề phức tạp nhằm quản lý công việc và thời gian hiệu quả trong môi trường đa văn hoá.'),
(97, 18, 'PLO7', 'ĐÁNH GIÁ chất lượng công việc trong các hoạt động liên quan tới Ngôn ngữ Anh chuyên sâu Kinh doanh – CNTT.'),
(98, 18, 'PLO8', 'THIẾT LẬP kỹ năng giao tiếp, tư duy ngôn ngữ logic, phản biện trong việc sử dụng Ngôn ngữ Anh chuyên ngành.'),
(99, 18, 'PLO9', 'THIẾT LẬP kỹ năng làm việc độc lập, làm việc theo nhóm trong môi trường đa văn hoá.'),
(100, 18, 'PLO10', 'ĐÁNH GIÁ hiệu quả công việc để định hướng, lập kế hoạch trong các hoạt động chuyên môn.'),
(101, 18, 'PLO11', 'XÁC ĐỊNH đúng đắn phẩm chất đạo đức cá nhân, nghề nghiệp, xã hội trong sử dụng Ngôn ngữ Anh chuyên ngành.'),
(102, 23, 'PLO1', 'Vận dụng các kiến thức nền tảng về khoa học chính trị, xã hội, pháp luật, phương pháp luận, CNTT để học tập và làm việc.'),
(103, 23, 'PLO2', 'Vận dụng kiến thức cốt lõi về marketing số để hiểu thị trường, hành vi khách hàng phục vụ xây dựng kế hoạch marketing.'),
(104, 23, 'PLO3', 'Vận dụng các kiến thức căn bản và các công cụ về truyền thông, truyền thông số và kiến thức liên quan.'),
(105, 23, 'PLO4', 'Vận dụng hiệu quả các công nghệ số vào hoạt động truyền thông và marketing giúp gia tăng giá trị, giảm chi phí.'),
(106, 23, 'PLO5', 'Phối hợp kiến thức truyền thông, marketing và công nghệ số để triển khai dự án quảng cáo, quản trị truyền thông đa phương tiện.'),
(107, 23, 'PLO6', 'Xây dựng và thực thi chiến lược, kế hoạch, dự án khởi nghiệp, kinh doanh gắn truyền thông và marketing số.'),
(108, 23, 'PLO7', 'Phát triển kỹ năng nghiên cứu, phân tích thị trường, dự báo hành vi khách hàng; kỹ năng xây dựng thương hiệu, sáng tạo nội dung.'),
(109, 23, 'PLO8', 'Phối hợp sáng tạo kỹ năng phát hiện và giải quyết vấn đề trong lập kế hoạch, đánh giá hiệu quả dự án tích hợp truyền thông.'),
(110, 23, 'PLO9', 'Sử dụng tốt tiếng Anh (Bậc 4/6) và tiếng Anh chuyên ngành Truyền thông marketing số.'),
(111, 23, 'PLO10', 'Xác định khả năng làm việc nhóm, lập kế hoạch, giao việc, tư duy và giải quyết vấn đề, kiểm soát và truyền thông hiệu quả.'),
(112, 23, 'PLO11', 'Đạt kỹ năng sử dụng tin học văn phòng nâng cao; phần mềm xử lý dữ liệu, mô phỏng về hoạt động truyền thông số.'),
(113, 23, 'PLO12', 'Tự lập kế hoạch, triển khai, đánh giá và cải thiện hiệu quả các hoạt động marketing; chủ động tự học tập.'),
(114, 23, 'PLO13', 'Làm việc độc lập hoặc theo nhóm; chấp nhận giá trị khác biệt; năng lực dẫn dắt, giám sát công việc.'),
(115, 23, 'PLO14', 'Thực hành tư duy đổi mới sáng tạo, tự định hướng, đưa ra kết luận chuyên môn và bảo vệ quan điểm cá nhân.'),
(116, 23, 'PLO15', 'Bản lĩnh vượt qua khó khăn, có trách nhiệm đối với cá nhân, tập thể, tạo giá trị chung cho cộng đồng.'),
(117, 23, 'PLO16', 'Có thái độ đúng đắn về truyền thông và marketing; tuân thủ luật pháp và các quy định; mang lại giá trị cho cộng đồng.'),
(118, 23, 'PLO17', 'Thể hiện thái độ tích cực, yêu nghề; ý thức tổ chức kỷ luật, trách nhiệm và đạo đức nghề nghiệp thời đại số.'),
(119, 23, 'PLO18', 'Tham gia nhiệt tình các hoạt động xã hội; có ý thức phục vụ nhân dân.'),
(120, 23, 'PLO19', 'Thể hiện phẩm chất chính trị và đạo đức cá nhân phù hợp với xã hội; chấp hành các quy tắc công cộng.'),
(121, 23, 'PLO20', 'Tuân thủ Hiến pháp và Pháp luật; tham gia bảo vệ an ninh, có ý thức xây dựng đất nước.'),
(122, 22, 'PLO1', 'Vận dụng kiến thức cơ bản về kinh tế học, quản trị học, luật kinh doanh và công nghệ thông tin.'),
(123, 22, 'PLO2', 'Áp dụng kiến thức chuyên sâu về thương mại điện tử, chiến lược số, marketing kỹ thuật số, hành vi khách hàng trực tuyến.'),
(124, 22, 'PLO3', 'Đánh giá tác động của toàn cầu hóa, kinh tế số, công nghiệp 4.0 và phát triển bền vững đến môi trường kinh doanh số.'),
(125, 22, 'PLO4', 'Vận dụng kiến thức về dữ liệu lớn (big data), AI, điện toán đám mây và tự động hóa để cải thiện hiệu quả kinh doanh.'),
(126, 22, 'PLO5', 'Phân tích và đề xuất các mô hình kinh doanh số phù hợp với xu thế công nghệ và hành vi tiêu dùng hiện đại.'),
(127, 22, 'PLO6', 'Tích hợp tư duy phân tích, tư duy hệ thống và tư duy công nghệ trong thiết kế giải pháp chuyển đổi số.'),
(128, 22, 'PLO7', 'Phân tích và khai thác dữ liệu từ các hệ thống thông tin để hỗ trợ ra quyết định trong doanh nghiệp số.'),
(129, 22, 'PLO8', 'Thiết kế, triển khai và đánh giá hiệu quả các chiến dịch marketing kỹ thuật số, quản lý nội dung số và trải nghiệm (UX).'),
(130, 22, 'PLO9', 'Phát triển, vận hành hoạt động thương mại điện tử, ứng dụng quản trị hệ thống CRM, ERP trong doanh nghiệp.'),
(131, 22, 'PLO10', 'Phối hợp tổ chức thực hiện các dự án kinh doanh số có sự tham gia đa lĩnh vực và đa quốc gia.'),
(132, 22, 'PLO11', 'Xây dựng kỹ năng giao tiếp chuyên nghiệp, thuyết trình hiệu quả và đàm phán trong môi trường số hoá.'),
(133, 22, 'PLO12', 'Làm việc nhóm hiệu quả, tổ chức điều phối hoạt động nhóm trên nền tảng công nghệ số và tư duy phản biện.'),
(134, 22, 'PLO13', 'Ứng dụng thành thạo công cụ số như Google Workspace, Canva, và các công cụ nghiên cứu định lượng (Power BI, Tableau).'),
(135, 22, 'PLO14', 'Sử dụng tốt tiếng Anh (tương đương bậc 4/6); có kỹ năng sử dụng tốt tiếng Anh chuyên ngành kinh doanh số.'),
(136, 22, 'PLO15', 'Chủ động trong học tập suốt đời, cập nhật kiến thức công nghệ và xu hướng thị trường mới.'),
(137, 22, 'PLO16', 'Xác định được vai trò, trách nhiệm và đạo đức nghề nghiệp, bao gồm quyền riêng tư, bảo mật dữ liệu.'),
(138, 22, 'PLO17', 'Tự tin đưa ra quyết định, thích nghi nhanh và sáng tạo trong điều kiện môi trường kinh doanh liên tục thay đổi.'),
(139, 22, 'PLO18', 'Xây dựng tư duy khởi nghiệp, sáng tạo, đổi mới, có khả năng dẫn dắt các ý tưởng công nghệ và kinh doanh số.'),
(140, 15, 'PLO1', 'Vận dụng các kiến thức cơ bản về khoa học xã hội, khoa học chính trị, pháp luật và ngoại ngữ (tiếng Anh).'),
(141, 15, 'PLO2', 'Vận dụng kiến thức cơ bản trong các lĩnh vực kinh tế, xã hội học làm nền tảng triển khai các hoạt động Marketing.'),
(142, 15, 'PLO3', 'Đánh giá tác động của môi trường kinh doanh, toàn cầu hoá, nền kinh tế 4.0, đổi mới và phát triển bền vững đến Marketing.'),
(143, 15, 'PLO4', 'Xác định được các học thuyết và quy luật kinh tế, cách thức vận hành của thị trường, vai trò của chính phủ.'),
(144, 15, 'PLO5', 'Áp dụng kiến thức Marketing để lập kế hoạch, triển khai tổ chức hoạt động quản trị marketing trong doanh nghiệp.'),
(145, 15, 'PLO6', 'Vận dụng các kiến thức chuyên ngành để tổ chức: Quản trị kênh phân phối, truyền thông số, quản trị sản phẩm.'),
(146, 15, 'PLO7', 'Áp dụng kĩ năng tổng hợp và phân tích thông tin dữ liệu để thực hiện các dự án hoặc chiến dịch Marketing.'),
(147, 15, 'PLO8', 'Vận dụng kỹ năng tự học tập và cập nhật kiến thức từ sách, báo cáo khoa học và các tài liệu bổ trợ.'),
(148, 15, 'PLO9', 'Phát triển năng lực phân tích vấn đề khoa học, tư duy sáng tạo, đổi mới trong tiếp cận và ứng dụng công nghệ.'),
(149, 15, 'PLO10', 'Xây dựng kỹ năng giao tiếp, đàm phán, thuyết phục; giao tiếp tiếng Anh trình độ bậc 4 (B2 Châu Âu) hoặc IELTS 5.5.'),
(150, 15, 'PLO11', 'Xác định khả năng làm việc nhóm, phối hợp và hỗ trợ lẫn nhau, giao việc theo đúng khả năng của các thành viên.'),
(151, 15, 'PLO12', 'Vận dụng kỹ năng sử dụng phần mềm tin học văn phòng và các kỹ thuật để nghiên cứu và lập kế hoạch Marketing.'),
(152, 15, 'PLO13', 'Xác định khả năng tự chủ trong nghiên cứu, sử dụng thành thạo kiến thức để đưa ra giải pháp cho doanh nghiệp.'),
(153, 15, 'PLO14', 'Xác định năng lực phát hiện, giải quyết vấn đề; đưa ra được những sáng kiến có giá trị để giải quyết vướng mắc.'),
(154, 15, 'PLO15', 'Xây dựng phẩm chất đạo đức tốt, trung thực, có trách nhiệm, chủ động, chính trực trong học tập và công việc.'),
(155, 16, 'PLO1', 'Vận dụng các lý thuyết, phương pháp luận của chủ nghĩa duy vật biện chứng, lịch sử; ngoại ngữ (tiếng Anh).'),
(156, 16, 'PLO2', 'Vận dụng kiến thức kinh tế, lịch sử, văn hóa, tâm lí học làm nền tảng nghiên cứu lĩnh vực quản lý và kinh doanh.'),
(157, 16, 'PLO3', 'Hiểu và vận dụng những kiến thức cơ bản về nhà nước và pháp luật để đưa ra phương án giải quyết các vấn đề kinh tế.'),
(158, 16, 'PLO4', 'Khai thác kiến thức về học thuyết kinh tế, cách thức vận hành thị trường để phân tích, ra quyết định quản lý.'),
(159, 16, 'PLO5', 'Lý giải các kiến thức khoa học quản lý vào quá trình khởi sự doanh nghiệp, xử lý các vấn đề quản trị.'),
(160, 16, 'PLO6', 'Vận dụng kiến thức khoa học quản lý để đề xuất, triển khai chiến lược tổng thể và chiến lược chức năng.'),
(161, 16, 'PLO7', 'Vận dụng kỹ năng tổng hợp và phân tích thông tin, dữ liệu để giải quyết các tình huống quản trị thực tiễn.'),
(162, 16, 'PLO8', 'Vận dụng kỹ năng tự học tập và cập nhật kiến thức từ sách, báo cáo khoa học và các tài liệu bổ trợ.'),
(163, 16, 'PLO9', 'Xây dựng năng lực phân tích vấn đề một cách khoa học, tư duy sáng tạo, đổi mới trong tiếp cận công nghệ.'),
(164, 16, 'PLO10', 'Xây dựng kỹ năng giao tiếp, đàm phán; giao tiếp tiếng Anh trình độ bậc 4 (B2 Châu Âu) hoặc IELTS 6.0.'),
(165, 16, 'PLO11', 'Xây dựng kỹ năng làm việc nhóm, chia sẻ các giải pháp quản trị và thích ứng với môi trường kỷ nguyên số.'),
(166, 16, 'PLO12', 'Thiết lập kỹ năng sử dụng phần mềm Microsoft Office và một số phần mềm thống kê trong phân tích kinh doanh.'),
(167, 16, 'PLO13', 'Thiết lập khả năng tự chủ trong nghiên cứu, đưa ra giải pháp cho vấn đề quản trị của doanh nghiệp.'),
(168, 16, 'PLO14', 'Thiết lập năng lực phát hiện, giải quyết vấn đề; đưa ra sáng kiến có giá trị trong hoạt động kinh doanh.'),
(169, 16, 'PLO15', 'Xây dựng phẩm chất đạo đức tốt, trung thực, có trách nhiệm, chủ động, chính trực trong học tập và công việc.');
